def solve():
    n, s, k = map(int, input().split())
    closed = set(map(int, input().split()))

    # Check if current floor is open
    if s not in closed:
        return 0

    # Search outward from floor s
    distance = 1
    while True:
        # Check floor s - distance
        if s - distance >= 1 and s - distance not in closed:
            return distance
        # Check floor s + distance
        if s + distance <= n and s + distance not in closed:
            return distance
        distance += 1

t = int(input())
for _ in range(t):
    print(solve())
